      const end = parseInt(endStr, 10);
      if (isNaN(start) || isNaN(end)) throw new Error(`Invalid range in "${token}"`);
      assertInRange(start, min, max, token);
      assertInRange(end, min, max, token);
      if (start > end) throw new Error(`Range start > end in "${token}"`);
      return rangeArray(start, end, step);
    }

    throw new Error(`Invalid step expression "${token}"`);
  }

  // Wildcard
  if (token === "*") {
    return rangeArray(min, max);
  }

  // Range: start-end
  if (token.includes("-")) {
    const [startStr, endStr] = token.split("-");
