function parseField(expr: string, config: FieldConfig): number[] {
  const { min, max } = config;

  const allValues = (): number[] =>
    Array.from({ length: max - min + 1 }, (_, i) => i + min);

  // Comma-separated list — split and recurse
  if (expr.includes(",")) {
    const parts = expr.split(",");
    const values = new Set<number>();
    for (const part of parts) {
      for (const v of parseField(part.trim(), config)) {
        values.add(v);
      }
    }
    return Array.from(values).sort((a, b) => a - b);
  }

  // Step value: */N or start-end/N
  if (expr.includes("/")) {
    const [rangePart, stepStr] = expr.split("/");
    const step = parseInt(stepStr, 10);
    if (isNaN(step) || step <= 0) throw new Error(`Invalid step value in "${expr}"`);

    let start: number;
    let end: number;

    if (rangePart === "*") {
      start = min;
      end = max;
    } else if (rangePart.includes("-")) {
      [start, end] = parseRange(rangePart, config);
    } else {
      start = parseInt(rangePart, 10);
      end = max;
    }

    if (start < min || end > max) {
      throw new Error(`Value out of range [${min}-${max}] in "${expr}"`);
    }

    const values: number[] = [];
    for (let i = start; i <= end; i += step) {
      values.push(i);
    }
    return values;
  }

  // Range: start-end
  if (expr.includes("-")) {
    const [start, end] = parseRange(expr, config);
    if (start < min || end > max || start > end) {
      throw new Error(`Invalid range in "${expr}" for bounds [${min}-${max}]`);
    }
    return Array.from({ length: end - start + 1 }, (_, i) => i + start);
  }

  // Wildcard
  if (expr === "*") {
    return allValues();
  }

  // Single number
  const num = parseInt(expr, 10);
  if (isNaN(num)) throw new Error(`Invalid cron field value: "${expr}"`);
  if (num < min || num > max) {
    throw new Error(`Value ${num} out of range [${min}-${max}]`);
  }
  return [num];
}

