function assertInRange(value: number, min: number, max: number, context: string): void {
  if (value < min || value > max) {
    throw new RangeError(`Value ${value} out of range [${min}, ${max}] in field "${context}"`);
  }
}

function parseSegment(segment: string, config: FieldConfig, fieldName: string): number[] {
  const { min, max } = config;

  // Wildcard
  if (segment === "*") {
    return range(min, max);
  }

  // Step with wildcard: */N
  const stepWildcardMatch = segment.match(/^\*\/(\d+)$/);
  if (stepWildcardMatch) {
    const step = parseInt(stepWildcardMatch[1], 10);
    if (step <= 0) throw new RangeError(`Step value must be positive in field "${fieldName}"`);
    return range(min, max, step);
  }

  // Range with optional step: N-M or N-M/S
  const rangeMatch = segment.match(/^(\d+)-(\d+)(?:\/(\d+))?$/);
  if (rangeMatch) {
    const from = parseInt(rangeMatch[1], 10);
    const to = parseInt(rangeMatch[2], 10);
    const step = rangeMatch[3] ? parseInt(rangeMatch[3], 10) : 1;
    assertInRange(from, min, max, fieldName);
    assertInRange(to, min, max, fieldName);
    if (from > to) throw new RangeError(`Range start ${from} exceeds end ${to} in field "${fieldName}"`);
    if (step <= 0) throw new RangeError(`Step value must be positive in field "${fieldName}"`);
    return range(from, to, step);
  }

  // Single number
  const numMatch = segment.match(/^(\d+)$/);
  if (numMatch) {
    const value = parseInt(numMatch[1], 10);
    assertInRange(value, min, max, fieldName);
    return [value];
  }

  throw new SyntaxError(`Invalid cron segment "${segment}" in field "${fieldName}"`);
}

function parseField(field: string, config: FieldConfig, fieldName: string): number[] {
  const segments = field.split(",");
  if (segments.length === 0) {
    throw new SyntaxError(`Empty field "${fieldName}"`);
  }

  const values = new Set<number>();
  for (const segment of segments) {
    const trimmed = segment.trim();
    if (!trimmed) throw new SyntaxError(`Empty segment in field "${fieldName}"`);
    for (const v of parseSegment(trimmed, config, fieldName)) {
      values.add(v);
    }
  }

  return Array.from(values).sort((a, b) => a - b);
}

export default function parseCron(expression: string): CronFields {
  if (typeof expression !== "string" || !expression.trim()) {
    throw new SyntaxError("Cron expression must be a non-empty string");
  }

  const fields = expression.trim().split(/\s+/);
  if (fields.length !== 5) {
    throw new SyntaxError(`Expected 5 fields, got ${fields.length}`);
  }

  const result = {} as CronFields;
  for (let i = 0; i < 5; i++) {
    const name = FIELD_NAMES[i];
    result[name] = parseField(fields[i], FIELD_CONFIGS[i], name);
  }

  return result;
}

export interface CronFields {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

const FIELD_RANGES: Record<keyof CronFields, [number, number]> = {
  minute: [0, 59],
  hour: [0, 23],
  dayOfMonth: [1, 31],
  month: [1, 12],
  dayOfWeek: [0, 6],
};

function expandField(expr: string, min: number, max: number): number[] {
  const full = Array.from({ length: max - min + 1 }, (_, i) => i + min);

  if (expr === "*") return full;

  // Step: */n or range/n
  if (expr.includes("/")) {
    const [rangePart, stepStr] = expr.split("/");
    const step = parseInt(stepStr, 10);
    if (isNaN(step) || step <= 0) throw new Error(`Invalid step in "${expr}"`);

    let base: number[];
    if (rangePart === "*") {
      base = full;
    } else if (rangePart.includes("-")) {
      base = expandRange(rangePart, min, max);
    } else {
      const start = parseInt(rangePart, 10);
      if (isNaN(start)) throw new Error(`Invalid step expression "${expr}"`);
      base = full.filter((v) => v >= start);
    }

    return base.filter((_, i) => i % step === 0);
  }

  // Comma-separated list
  if (expr.includes(",")) {
    const values = expr.split(",").flatMap((part) => expandField(part.trim(), min, max));
    return [...new Set(values)].sort((a, b) => a - b);
  }

  // Range: a-b
  if (expr.includes("-")) {
    return expandRange(expr, min, max);
  }

  // Single number
  const val = parseInt(expr, 10);
  if (isNaN(val)) throw new Error(`Invalid value "${expr}"`);
  if (val < min || val > max) throw new Error(`Value ${val} out of range [${min}, ${max}]`);
  return [val];
}

function expandRange(expr: string, min: number, max: number): number[] {
  const [startStr, endStr] = expr.split("-");
  const start = parseInt(startStr, 10);
  const end = parseInt(endStr, 10);
  if (isNaN(start) || isNaN(end)) throw new Error(`Invalid range "${expr}"`);
  if (start < min || end > max || start > end)
    throw new Error(`Range "${expr}" out of bounds [${min}, ${max}]`);
  return Array.from({ length: end - start + 1 }, (_, i) => i + start);
}

export default function parseCron(expression: string): CronFields {
  const parts = expression.trim().split(/\s+/);
  if (parts.length !== 5) throw new Error(`Expected 5 fields, got ${parts.length}`);

  const fieldNames = Object.keys(FIELD_RANGES) as (keyof CronFields)[];

  return fieldNames.reduce((acc, field, i) => {
    const [min, max] = FIELD_RANGES[field];
    acc[field] = expandField(parts[i], min, max);
    return acc;
  }, {} as CronFields);
}

interface CronFields {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

type FieldConfig = { min: number; max: number };

const FIELD_CONFIGS: FieldConfig[] = [
  { min: 0, max: 59 },  // minute
  { min: 0, max: 23 },  // hour
  { min: 1, max: 31 },  // dayOfMonth
  { min: 1, max: 12 },  // month
  { min: 0, max: 7 },   // dayOfWeek
];

function range(start: number, end: number): number[] {
  const result: number[] = [];
  for (let i = start; i <= end; i++) result.push(i);
  return result;
}

function parseField(expr: string, config: FieldConfig): number[] {
  const { min, max } = config;

  // Comma-separated list
  if (expr.includes(",")) {
    const values = expr.split(",").flatMap((part) => parseField(part.trim(), config));
    return [...new Set(values)].sort((a, b) => a - b);
  }

  // Wildcard
  if (expr === "*") {
    return range(min, max);
  }

  // Step value: */n or start-end/n
  if (expr.includes("/")) {
    const [rangePart, stepStr] = expr.split("/");
    const step = parseInt(stepStr, 10);

    if (isNaN(step) || step <= 0) {
      throw new Error(`Invalid step value in expression: "${expr}"`);
    }

    let start: number;
    let end: number;

    if (rangePart === "*") {
      start = min;
      end = max;
    } else if (rangePart.includes("-")) {
      const [s, e] = rangePart.split("-").map((v) => parseInt(v, 10));
      start = s;
      end = e;
    } else {
      start = parseInt(rangePart, 10);
      end = max;
    }

    if (isNaN(start) || isNaN(end) || start < min || end > max || start > end) {
      throw new Error(`Invalid range in expression: "${expr}" (valid: ${min}-${max})`);
    }

    const result: number[] = [];
    for (let i = start; i <= end; i += step) result.push(i);
    return result;
  }

  // Range: start-end
  if (expr.includes("-")) {
    const [startStr, endStr] = expr.split("-");
    const start = parseInt(startStr, 10);
    const end = parseInt(endStr, 10);

    if (isNaN(start) || isNaN(end) || start < min || end > max || start > end) {
      throw new Error(`Invalid range: "${expr}" (valid: ${min}-${max})`);
    }

    return range(start, end);
  }

  // Single number
  const value = parseInt(expr, 10);

  if (isNaN(value) || value < min || value > max) {
    throw new Error(`Value ${expr} out of range (valid: ${min}-${max})`);
  }

  return [value];
}

export default function parseCron(expression: string): CronFields {
  const parts = expression.trim().split(/\s+/);

  if (parts.length !== 5) {
    throw new Error(`Expected 5 fields, got ${parts.length}: "${expression}"`);
  }

  const [minuteExpr, hourExpr, domExpr, monthExpr, dowExpr] = parts;
  const configs = FIELD_CONFIGS;

  const dayOfWeekValues = parseField(dowExpr, configs[4]);
  // Normalize: treat 7 as 0 (both represent Sunday)
  const normalizedDayOfWeek = [...new Set(dayOfWeekValues.map((v) => (v === 7 ? 0 : v)))].sort(
    (a, b) => a - b,
  );

  return {
    minute: parseField(minuteExpr, configs[0]),
    hour: parseField(hourExpr, configs[1]),
    dayOfMonth: parseField(domExpr, configs[2]),
    month: parseField(monthExpr, configs[3]),
    dayOfWeek: normalizedDayOfWeek,
  };
}

export interface CronFields {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

interface FieldConfig {
  min: number;
  max: number;
}

const FIELD_CONFIGS: FieldConfig[] = [
  { min: 0, max: 59 },  // minute
  { min: 0, max: 23 },  // hour
  { min: 1, max: 31 },  // dayOfMonth
  { min: 1, max: 12 },  // month
  { min: 0, max: 6 },   // dayOfWeek
];

function range(from: number, to: number, step = 1): number[] {
  if (from > to) throw new Error(`Invalid range: ${from}-${to}`);
  const result: number[] = [];
  for (let i = from; i <= to; i += step) result.push(i);
  return result;
}

function parseField(expr: string, config: FieldConfig): number[] {
  const { min, max } = config;

  // Comma-separated list
  if (expr.includes(",")) {
    const values = expr.split(",").flatMap((part) => parseField(part.trim(), config));
    const unique = [...new Set(values)].sort((a, b) => a - b);
    return unique;
  }

  // Wildcard with optional step: * or */n
  if (expr.startsWith("*")) {
    if (expr === "*") return range(min, max);
    if (expr.startsWith("*/")) {
      const step = parseInt(expr.slice(2), 10);
      if (isNaN(step) || step < 1) throw new Error(`Invalid step value: ${expr}`);
      return range(min, max, step);
    }
    throw new Error(`Invalid expression: ${expr}`);
  }

  // Range with optional step: a-b or a-b/n
  if (expr.includes("-")) {
    const [rangePart, stepPart] = expr.split("/");
    const [startStr, endStr] = rangePart!.split("-");
    const start = parseInt(startStr!, 10);
    const end = parseInt(endStr!, 10);
    const step = stepPart !== undefined ? parseInt(stepPart, 10) : 1;

    if (isNaN(start) || isNaN(end) || isNaN(step)) throw new Error(`Invalid range: ${expr}`);
    if (start < min || end > max) throw new Error(`Range ${expr} out of bounds [${min}-${max}]`);
    if (step < 1) throw new Error(`Invalid step: ${step}`);

    return range(start, end, step);
  }

  // Plain number
  const num = parseInt(expr, 10);
  if (isNaN(num)) throw new Error(`Invalid value: ${expr}`);
  if (num < min || num > max) throw new Error(`Value ${num} out of bounds [${min}-${max}]`);
  return [num];
}

export function parseCron(expression: string): CronFields {
  const parts = expression.trim().split(/\s+/);
  if (parts.length !== 5) {
    throw new Error(`Expected 5 fields, got ${parts.length}: "${expression}"`);
  }

  const [minuteExpr, hourExpr, domExpr, monthExpr, dowExpr] = parts as [string, string, string, string, string];

  return {
    minute: parseField(minuteExpr, FIELD_CONFIGS[0]!),
    hour: parseField(hourExpr, FIELD_CONFIGS[1]!),
    dayOfMonth: parseField(domExpr, FIELD_CONFIGS[2]!),
    month: parseField(monthExpr, FIELD_CONFIGS[3]!),
    dayOfWeek: parseField(dowExpr, FIELD_CONFIGS[4]!),
  };
}

export default parseCron;

export interface CronExpression {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

const FIELD_RANGES: Record<string, [number, number]> = {
  minute: [0, 59],
  hour: [0, 23],
  dayOfMonth: [1, 31],
  month: [1, 12],
  dayOfWeek: [0, 7],
};

const expandRange = (min: number, max: number): number[] =>
  Array.from({ length: max - min + 1 }, (_, i) => min + i);

const validateBounds = (value: number, min: number, max: number, fieldName: string): void => {
  if (value < min || value > max) {
    throw new Error(`Value ${value} out of range [${min}, ${max}] for field "${fieldName}"`);
  }
};

function parseField(field: string, fieldName: string): number[] {
  const [min, max] = FIELD_RANGES[fieldName];

  if (field.includes(",")) {
    const values = field
      .split(",")
      .flatMap((part) => parseField(part.trim(), fieldName));
    return [...new Set(values)].sort((a, b) => a - b);
  }

  if (field === "*") {
    return expandRange(min, max);
  }

  if (field.includes("/")) {
    const [rangeOrWild, stepStr] = field.split("/");
    const step = parseInt(stepStr, 10);

    if (isNaN(step) || step <= 0) {
      throw new Error(`Invalid step value in field "${field}"`);
    }

    let start: number;
    let end: number;

    if (rangeOrWild === "*") {
      start = min;
      end = max;
    } else if (rangeOrWild.includes("-")) {
      const [s, e] = rangeOrWild.split("-").map((v) => parseInt(v, 10));
      start = s;
      end = e;
    } else {
      start = parseInt(rangeOrWild, 10);
      end = max;
    }

    if (isNaN(start) || isNaN(end)) {
      throw new Error(`Invalid range in field "${field}"`);
    }

    validateBounds(start, min, max, fieldName);
    validateBounds(end, min, max, fieldName);

    const values: number[] = [];
    for (let i = start; i <= end; i += step) {
      values.push(i);
    }
    return values;
  }

  if (field.includes("-")) {
    const [startStr, endStr] = field.split("-");
    const start = parseInt(startStr, 10);
    const end = parseInt(endStr, 10);

    if (isNaN(start) || isNaN(end)) {
      throw new Error(`Invalid range "${field}" for field "${fieldName}"`);
    }
    if (start > end) {
      throw new Error(`Invalid range "${field}": start exceeds end`);
    }

    validateBounds(start, min, max, fieldName);
    validateBounds(end, min, max, fieldName);

    return expandRange(start, end);
  }

  const value = parseInt(field, 10);

  if (isNaN(value)) {
    throw new Error(`Invalid value "${field}" for field "${fieldName}"`);
  }

  validateBounds(value, min, max, fieldName);

  return [value];
}

export default function parseCron(expression: string): CronExpression {
  const fields = expression.trim().split(/\s+/);

  if (fields.length !== 5) {
    throw new Error(
      `Invalid cron expression: expected 5 fields, got ${fields.length}`
    );
  }

  const [minuteField, hourField, dayOfMonthField, monthField, dayOfWeekField] =
    fields;

  return {
    minute: parseField(minuteField, "minute"),
    hour: parseField(hourField, "hour"),
    dayOfMonth: parseField(dayOfMonthField, "dayOfMonth"),
    month: parseField(monthField, "month"),
    dayOfWeek: parseField(dayOfWeekField, "dayOfWeek"),
  };
}
